15	function isNeighbor([x, y]: Cell, [ox, oy]: Cell): boolean {
16	  const dx = Math.abs(ox - x);
17	  const dy = Math.abs(oy - y);
18	  const isWithinRange = dx <= 1 && dy <= 1;
19	  const isSameCell = dx === 0 && dy === 0;
20	  return isWithinRange && !isSameCell;
21	}
